('ONET-FIRST_LINE_SUPERVISORS_OF_GAMBLING_SERVICES_WORK', 'source_onet_first_line_supervisors_of_gambling_services_workers', 'First-Line Supervisors of Gambling Services Workers', 'First-Line Supervisors of Gambling Services Workers is an imported ONET role/occupation concept. It needs TALLENTIN normalization before production routing.', 'role_title', 'Directly supervise and coordinate activities of workers in assigned gambling areas. May circulate among tables, observe operations, and ensure that stations and games are covered for each shift. May verify and pay off jackpots. May reset slot machines after payoffs and make repairs or adjustments to slot machines or recommend removal of slot machines for repair. May plan and organize activities and services for guests in hotels/casinos.', ARRAY['Blackjack Pit Boss','Blackjack Supervisor','Cage Supervisor','Cardroom Manager','Cardroom Supervisor','Casino Floor Runner','Casino Floor Supervisor','Casino Floorperson','Casino Manager','Casino Services Supervisor','Casino Shift Manager (CSM)','Casino Slot Supervisor','Casino Supervisor','Contract Runner','Dual Rate Supervisor','Electronic Gambling Device Supervisor','Electronic Gaming Device Supervisor','Executive Casino Host','Floor Person','Floor Supervisor','Floorperson','Gambling Floor Supervisor','Gambling Supervisor','Gaming Floor Supervisor','Hourly Manager','Key Person','Lottery Office Manager','Pit Boss','Pit Supervisor','Player Services Supervisor','Poker Room Manager','Poker Room Supervisor','Poker Supervisor','Security Supervisor','Slot Floor Person','Slot Floor Supervisor','Slot Key Person','Slot Machine Floor Person','Slot Machine Key Person','Slot Manager','Slot Shift Manager','Slot Shift Supervisor','Slot Supervisor','Slot Technical Supervisor','Table Games Dual Rate Supervisor','Table Games Floor Supervisor','Table Games Manager','Table Games Pit Manager','Table Games Shift Manager','Table Games Supervisor']::text[], ARRAY['First-Line Supervisors of Gamblin